    [40192] = { 18545, 1, 128, "奥的灰烬", "奥是凯尔萨斯·逐日者心爱的宠物，他经常吹嘘死亡永远无法带走它。也许他是对的。", 0, "|cFFFFD200掉落：|r 凯尔萨斯·逐日者|n|cFFFFD200地点：|r 风暴要塞，风暴之眼" },
    [40212] = { 16597, 1, },
    [41252] = { 23408, 2, 0, "乌鸦领主", "其余的将被遗忘在地上行走，折断双翼，满载耻辱。——乌鸦的言语", 0, "|cFFFFD200掉落：|r 安苏|n|cFFFFD200区域：|r 塞泰克大厅（英雄）" },
    [41513] = { 23455, 1, 128, "黑色虚空灵龙", "在承诺带你飞向外域的尽头后，虚空灵龙最终也被艾泽拉斯的蔚蓝天空所吸引。", 1, "|cFFFFD200任务：|r 黑色虚空灵龙奥尼克西安|n|cFFFFD200区域：|r 沙塔斯城，外域" },
