    [41515] = { 23460, 1, 128, "深蓝虚空灵龙", "在承诺带你飞向外域的尽头后，虚空灵龙最终也被艾泽拉斯的蔚蓝天空所吸引。", 1, "|cFFFFD200任务：|r 深蓝虚空灵龙乔鲁斯|n|cFFFFD200区域：|r 沙塔斯城，外域" },
    [41516] = { 23458, 1, 128, "紫色虚空灵龙", "在承诺带你飞向外域的尽头后，虚空灵龙最终也被艾泽拉斯的蔚蓝天空所吸引。", 1, "|cFFFFD200任务：|r 紫色虚空灵龙玛尔法斯|n|cFFFFD200区域：|r 沙塔斯城，外域" },
    [41517] = { 23457, 1, 128, "翠绿虚空灵龙", "在承诺带你飞向外域的尽头后，虚空灵龙最终也被艾泽拉斯的蔚蓝天空所吸引。", 1, "|cFFFFD200任务：|r 翠绿虚空灵龙卓亚|n|cFFFFD200区域：|r 沙塔斯城，外域" },
