    [42776] = { 24003, 2, 64, "幽灵虎", "以真正的地精风格，兰德鲁·长射完全扼杀了这些神秘无实体坐骑的发行渠道。", 8, "|cFFFFD200集换式卡牌：|r 幽灵虎" },
    [42777] = { 24004, 2, 64, "迅捷幽灵虎", "历史学家声称这些无实体的野兽是在德拉诺爆炸时产生的，释放出的能量使世界的动植物发生了变异。", 8, "|cFFFFD200集换式卡牌：|r 幽灵虎" },
    [42929] = { 21635, 0, },
    [43688] = { 24379, 2, 64, "阿曼尼战熊", "只有最敏捷、勇闯祖阿曼巨魔神庙的英雄才能降服这些罕见的战斗坐骑。", 0, "|cFFFFD200绝版|r" },
