    [43899] = { 23588, 2, 64, "美酒节赛羊", "酿酒师们停止了这种坐骑的商业宣传活动，因为有人抱怨这些野兽在主城里“太神经质”以至于无法控制。", 6, "|cFFFFD200绝版|r" },
    [43900] = { 24368, 2, 0, "迅捷美酒节赛羊", "矮人们将这个品种的沉稳归功于严格的训练，但其他种族认为这与每天喂食烈性麦酒有关。", 0, "|cFFFFD200掉落：|r 桶型宝箱|n|cFFFFD200节日：|r 美酒节" },
    [43927] = { 24488, 1, 128, "塞纳里奥角鹰兽", "塞纳里奥议会的成员与他们的角鹰兽盟友有着悠久而繁荣的伙伴关系。当冲突不可避免时，塞纳里奥战斗角鹰兽就会被召唤参战。", 2, "|cFFFFD200商人：|r芬德林·迅矛|n|cFFFFD200区域：|r赞加沼泽，外域|n|cFFFFD200阵营：|r塞纳里奥远征队 - 崇拜|n|cFFFFD200花费：|r2000|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [44151] = { 24654, 1, 128, "涡轮加速飞行器", "只有最天才的工程师才有勇气和精力去创造一架兼具稳定性和安全性的飞行器。而涡轮加速更是疯狂之举！", 3, "|cFFFFD200专业：|r工程学" },
    [44153] = { 24653, 1, 128, "飞行器", "由于侏儒飞行器的机动性和速度，联盟空军的骨干主要由它们组成。", 3, "|cFFFFD200专业：|r工程学" },
    [44317] = { 21510, 1, 192, "无情虚空幼龙", "最凶猛的虚空幼龙被奖赏给那些在角斗士竞技场中展现出非凡实力与奉献精神的英雄。", 5, "|cFFFFD200绝版|r" },
