    [46197] = { 26192, 1, 64, "X-51虚空火箭", "X-51 最初被设计为一个巨型火箭的助推器，后来被确认能为单人乘员提供完美的推力。", 8, "|cFFFFD200集换式卡牌：|r X-51虚空火箭" },
    [46199] = { 26164, 1, 64, "X-51虚空火箭特别版", "它在安全设施上的不足，已经通过速度和拉风程度得到了弥补。胆小者慎用。", 8, "|cFFFFD200集换式卡牌：|r X-51虚空火箭" },
    [46628] = { 26131, 2, 0, "迅捷白色陆行鸟", "我可以怀疑凯尔萨斯王子的忠诚，但绝不怀疑他的品味。——埃隆朗", 0, "|cFFFFD200掉落：|r 凯尔萨斯·逐日者|n|cFFFFD200区域：|r 魔导师平台" },
