    [48025] = { 27153, 2, 0, "无头骑士的坐骑", "无论是洪水还是烈火，这家伙都会带你去你想去的地方。", 0, "|cFFFFD200掉落：|r 塞满战利品的南瓜|n|cFFFFD200节日：|r 万圣节|n" },
    [48027] = { 26439, 2, 0, "黑色战象", "异常好斗和凶猛的公雷象从象群中被挑选出来卖给星界商人。这些商人随后训练这些公象进行战斗，并将它们卖给不关心安全问题的买主。", 2, "|cFFFFD200商人：|r卡特尔中尉|n|cFFFFD200区域：|r暴风城|n|cFFFFD200花费：|r50000|TInterface\\PVPFrame\\PVP-Currency-Alliance:0|t" },
    [48778] = { 28302, 2, 0, "阿彻鲁斯死亡战马", "有些马仅仅是适应了黑暗。而这匹马生于黑暗，并由黑暗塑造。", 2, "|cFFFFD200训练师：|r 死亡骑士|n" },
    [48954] = { 27541, 2, 64, "迅捷斑马", "由于其固执的天性和咬人的倾向，斑马在艾泽拉斯很少被用作坐骑。", 7, "|cFFFFD200招募战友 |r" },
    [49193] = { 27637, 1, 192, "复仇虚空幼龙", "最凶猛的虚空幼龙被奖赏给那些在角斗士竞技场中展现出非凡实力与奉献精神的英雄。", 5, "|cFFFFD200绝版|r" },
    [49322] = { 27684, 2, 0, "迅捷斑马", "由于其固执的天性和咬人的倾向，斑马在艾泽拉斯很少被用作坐骑。", 7, "|cFFFFD200招募战友 |r" },
    [49378] = { 27706, 2, 64, "美酒节骑乘科多兽", "你已经记不清到底是怎么得到这只坐骑的了。话说回来，你在美酒节发生的事几乎都不记得了。", 6, "|cFFFFD200绝版|r" },
    [49379] = { 27707, 2, 0, "大型美酒节科多兽", "科伦·恐酒在酒桌上喝倒了一个牛头人德鲁伊之后赢得了这个奖品——而且那个德鲁伊当时还在熊形态。那是恐酒最自豪的时刻之一。", 0, "|cFFFFD200掉落：|r 桶型宝箱|n|cFFFFD200节日：|r 美酒节" },
