    [54729] = { 29582, 1, 128, "黑锋骨鹫", "不管你是死是活，你都得跟我走。", 2, "|cFFFFD200商人：|r恐怖指挥官萨拉诺尔|n|cFFFFD200区域：|r东瘟疫之地|n|cFFFFD200花费：|r1000|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [54753] = { 29596, 2, 0, "白色北极熊", "冰霜维库人认为，戴上北极熊爪子做成的项链会赋予他们超凡的力量。", 0, "|cFFFFD200掉落：|r 海德尼尔战利品|n|cFFFFD200地点：|r 风暴峭壁" },
    [55164] = { 29767, 2, 64, "迅捷幽灵狮鹫", "即便是死者，偶尔也需要搭个便车。", 5, "|cFFFFD200绝版|r" },
    [55293] = { 24379, 2, },
    [55531] = { 29929, 2, 4, "机械路霸", "制造和维护都非常困难，但这些摩托车通过纯粹的拉风程度弥补了它们的昂贵造价。", 3, "|cFFFFD200专业：|r工程学" },
    [58615] = { 31124, 1, 192, "野蛮虚空幼龙", "最凶猛的虚空幼龙被奖赏给那些在角斗士竞技场中展现出非凡实力与奉献精神的英雄。", 2, "|cFFFFD200绝版|r" },
    [58819] = { 14561, 2, },
    [58983] = { 31319, 2, 0, "暴雪巨熊", "每当你骑上这只坐骑，你都会忍不住想大喊：“散布恐惧，让战争的鱼人肆虐吧！”", 7, "|cFFFFD200促销活动：|r 暴雪嘉年华|n" },
    [58997] = { 31319, 2, },
    [58999] = { 31319, 2, },
    [59567] = { 31694, 1, 128, "蓝龙", "面对愤怒的巨龙时，一定要保持礼貌。", 0, "|cFFFFD200掉落：|r 阿莱克丝塔萨的礼物|n|cFFFFD200地点：|r 永恒之眼" },
    [59568] = { 31695, 1, 128, "碧蓝幼龙", "别夹在巨龙和他的怒火之间。", 0, "|cFFFFD200掉落：|r 阿莱克丝塔萨的礼物|n|cFFFFD200地点：|r 永恒之眼" },
    [59569] = { 31717, 1, 128, "青铜幼龙", "失去的时间永远找不回来。哦，算了，我找到了。——克罗米", 0, "|cFFFFD200掉落：|r 永恒腐蚀者|n|cFFFFD200区域：|r 净化斯坦索姆" },
    [59570] = { 31697, 1, 128, "红色幼龙", "你永远不该听信吟游诗人的幻想。除非有人先试图伤害它，否则巨龙绝不会伤害任何灵魂。", 2, "|cFFFFD200商人：|r希尔丝塔萨|n|cFFFFD200区域：|r龙骨荒野|n|cFFFFD200阵营：|r龙眠联军 - 崇拜|n|cFFFFD200花费：|r2000|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [59571] = { 31698, 1, 128, "暮光幼龙", "但最重要的规矩，你绝对不能忘记的规矩，不管他怎么哭，不管他怎么求，千万别在午夜之后喂他。", 0, "|cFFFFD200掉落：|r 萨塔里奥|n|cFFFFD200地点：|r 黑曜石圣殿" },
    [59572] = { 31699, 2, 64, "黑色北极熊", "牦牛人用黑色北极熊的皮毛进行宗教仪式，通常是在那些猎杀黑色北极熊的人的葬礼上。", 2, "|cFFFFD200绝版|r" },
    [59573] = { 31700, 2, },
    [59650] = { 31778, 1, 128, "黑龙", "把一头活着的巨龙排除在计划之外绝不是明智之举。", 0, "|cFFFFD200掉落：|r 萨塔里奥" },
    [59785] = { 31849, 2, 4, "黑色战象", "通常是温顺的野兽，这些聪明的动物与它们的骑手结下了深厚的羁绊，使它们在战斗中忠诚无畏。", 2, "|cFFFFD200商人：|r骑士达梅隆|n|cFFFFD200区域：|r冬拥湖|n|cFFFFD200花费：|r300|Hitem:43228|h|TInterface\\ICONS\\INV_Misc_Platnumdisks:0|t|h" },
    [59788] = { 31850, 2, 4, "黑色战象", "步履稳健、从容不迫，这些黑毛猛犸象因其冲向战场时的沉稳性情而备受珍视。", 2, "|cFFFFD200商人：|r石卫士木卡|n|cFFFFD200区域：|r冬拥湖|n|cFFFFD200花费：|r300|Hitem:43228|h|TInterface\\ICONS\\INV_Misc_Platnumdisks:0|t|h" },
    [59791] = { 31851, 2, 4, "长毛猛犸象", "作为猛犸象种族最初先祖的直系后代，长毛猛犸象被认为比它们短毛的表亲更加野蛮和原始。", 2, "|cFFFFD200商人：|r梅伊·弗兰丁|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r200|TINTERFACE\\ICONS\\Spell_Holy_ProclaimChampion:0|t" },
    [59793] = { 31852, 2, 4, "长毛猛犸象", "这种猛犸象的野生变种并非为了骑乘而繁育。大多数长毛猛犸象是在野外被捕获并由骑手驯服的，这就造就了一只凶猛、狡猾的坐骑。", 2, "|cFFFFD200商人：|r梅伊·弗兰丁|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r200|TINTERFACE\\ICONS\\Spell_Holy_ProclaimChampion:0|t" },
    [59797] = { 31854, 2, 4, "冰原猛犸象", "霍迪尔之子相信，骑乘冰白色的猛犸象能保护骑手免受冻伤和雪盲症的困扰。", 2, "|cFFFFD200商人：|r李奥霍夫|n|cFFFFD200区域：|r风暴峭壁|n|cFFFFD200阵营：|r霍迪尔之子 - 尊敬|n|cFFFFD200花费：|r1000|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [59799] = { 31855, 2, 4, "冰原猛犸象", "许多冰霜巨人声称，他们已经训练了他们最喜爱的白色猛犸象，通过它们的嚎叫声来引发雪崩。", 2, "|cFFFFD200商人：|r李奥霍夫|n|cFFFFD200区域：|r风暴峭壁|n|cFFFFD200阵营：|r霍迪尔之子 - 尊敬|n|cFFFFD200花费：|r1000|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [59802] = { 31857, 2, },
    [59804] = { 31858, 2, },
    [59961] = { 31902, 1, 128, "红色始祖幼龙", "维库人是第一个认识到它们潜力的。或者可能是第二个，这取决于你怎么看。", 5, "|cFFFFD200成就：|r英雄的荣耀|n|cFFFFD200分类：|r地下城和团队副本" },
    [59976] = { 31912, 1, 192, "黑色始祖幼龙", "专门为表彰那些在诺森德面临危险时表现出非凡韧性和坚韧的英雄而培育。", 2, "|cFFFFD200绝版|r" },
    [59996] = { 32151, 1, 128, "蓝色始祖幼龙", "风暴峭壁！在那里我们会找到足以载我冲锋陷阵的野兽。——无情的斯卡迪", 0, "|cFFFFD200掉落：|r 无情的斯卡迪|n|cFFFFD200区域：|r 乌特加德之巅" },
    [60002] = { 32153, 1, 128, "迷失始祖幼龙", "时间的唯一意义就是为了让所有事情不至于同时发生。", 0, "|cFFFFD200掉落：|r 迷失始祖幼龙|n|cFFFFD200区域：|r 风暴峭壁" },
    [60021] = { 32156, 1, 192, "被感染的始祖幼龙", "专门为表彰那些在诺森德面临危险时表现出极大勇气和毅力的英雄而培育。", 5, "|cFFFFD200绝版|r" },
    [60024] = { 32157, 1, 128, "紫色始祖幼龙", "我忍不住想，如果泰坦哪怕只多提升了一支巨龙军团，事情会不会变得不一样。——阿莱克丝塔萨", 5, "|cFFFFD200成就：|r千奇百怪的漫长旅行|n|cFFFFD200分类：|r世界事件" },
    [60025] = { 32158, 1, 128, "白化幼龙", "即便是巨龙原生DNA测试也无法确定白化幼龙是否与已知的巨龙军团有血缘关系。——布琳妮", 5, "|cFFFFD200成就：|r骑兵队长|n|cFFFFD200分类：|r综合" },
    [60114] = { 32206, 2, 4, "重型棕熊", "这只熊形坐骑的装甲经过了肯瑞托法师的魔法强化，大大提升了它的速度。", 2, "|cFFFFD200商人：|r梅伊·弗兰丁|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r750|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [60116] = { 32207, 2, 4, "重型棕熊", "当你骑在一头全副武装、以最高速度向联盟冲锋的巨熊背上时，你那“为了部落！”的战吼会显得更加威风凛凛。", 2, "|cFFFFD200商人：|r梅伊·弗兰丁|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r750|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [60118] = { 32203, 2, 4, "黑色战熊", "击杀部落的首领本身就是一种奖赏，但这只令人生畏的野兽是个极好的纪念品。", 5, "|cFFFFD200成就：|r为了联盟！|n|cFFFFD200分类：|r玩家对玩家" },
    [60119] = { 32205, 2, 4, "黑色战熊", "这只可怕的坐骑是用联盟领袖的鲜血换来的，不过就算没有奖励你也会去杀了他们的。", 5, "|cFFFFD200成就：|r为了部落！|n|cFFFFD200分类：|r玩家对玩家" },
    [60120] = { 32208, 1, },
    [60136] = { 32212, 0, 64, "大型商队猛犸象", "商人们在探索艾泽拉斯最危险的贸易路线时，只信任这种如雷鸣般、如小山般巨大的坐骑来保护他们。", 2, "|cFFFFD200绝版|r" },
    [60140] = { 32213, 0, 64, "大型商队猛犸象", "在艾泽拉斯的各条贸易路线上随处可见，这种沉稳、坚定的坐骑是前往偏远异国市场旅行的商人们的最爱。", 2, "|cFFFFD200绝版|r" },
    [60424] = { 32286, 2, 4, "麦克金尼尔的摩托车", "展示着卓越的工程学工艺，这辆摩托车是艾泽拉斯仅有的几款双人座驾之一。", 3, "|cFFFFD200专业：|r工程学" },
    [61229] = { 32335, 1, 132, "重型雪羽狮鹫", "好处是当它们发起攻击时，鲜血几乎永远不会弄脏它们的羽毛。——梅伊·弗兰丁", 2, "|cFFFFD200商人：|r梅伊·弗兰丁|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r2000|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [61230] = { 32336, 1, 132, "重型蓝色双足飞龙", "它们并非原产于诺森德，但它们对这里的寒冷适应得非常好。——梅伊·弗兰丁", 2, "|cFFFFD200商人：|r梅伊·弗兰丁|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r2000|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [61289] = { 23966, 0, },
    [61294] = { 32562, 1, 128, "绿色始祖幼龙", "维库人是第一个认识到它们潜力的。或者可能是第二个，这取决于你怎么看。", 0, "|cFFFFD200掉落：|r 裂开的卵" },
    [61309] = { 33030, 1, 1024, "华丽的飞毯", "标准配置包括坚固的霜纹布框架和真正的冰网蜘蛛丝缝线。备用枕头需另行购买。", 3, "|cFFFFD200专业：|r裁缝" },
    [61425] = { 32633, 2, 4, "旅行者的苔原猛犸象", "古老的文献描绘了商人们带着这些庞然大物穿越冰冻苔原的场景，这让学者们相信它们是最早被驯化的坐骑。", 2, "|cFFFFD200商人：|r梅伊·弗兰丁|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r20000|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [61442] = { 32634, 1, },
    [61444] = { 32635, 1, },
    [61446] = { 32636, 1, },
    [61447] = { 32640, 2, 4, "旅行者的苔原猛犸象", "无论是骑手还是商人，都只信任这种强壮坚定的猛犸象能安全地载他们穿越寒冷的苔原。", 2, "|cFFFFD200商人：|r梅伊·弗兰丁|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r20000|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [61451] = { 33029, 1, 1024, "飞毯", "跳上这张飞毯，去看看这个闪闪发光、灿烂夺目的艾泽拉斯世界，见证一个又一个奇迹。", 3, "|cFFFFD200专业：|r裁缝" },
    [61465] = { 31862, 2, 4, "重型黑色猛犸战象", "曾经被巨人用来运送重装士兵，这些巨大的猛犸战象可以轻松地搭载多名体型非巨人的骑手。", 0, "|cFFFFD200掉落：|r 首领掉落|n|cFFFFD200地点：|r 阿尔卡冯的宝库" },
    [61467] = { 31861, 2, 4, "重型黑色猛犸战象", "很少有猛犸战象生下来就比同类更强壮、更温顺。这些猛犸象被称为“重型”，可以将多名骑手运送到前线。", 0, "|cFFFFD200掉落：|r 首领掉落|n|cFFFFD200地点：|r 阿尔卡冯的宝库" },
    [61469] = { 31857, 2, 4, "重型冰原猛犸象", "在风暴峭壁狭窄结冰的崎岖小路上，这些猛犸象是冰霜巨人唯一信任的能运送大量货物和多名骑手的坐骑。", 2, "|cFFFFD200商人：|r李奥霍夫|n|cFFFFD200区域：|r风暴峭壁|n|cFFFFD200阵营：|r霍迪尔之子 - 崇拜|n|cFFFFD200花费：|r10000|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [61470] = { 31858, 2, 4, "重型冰原猛犸象", "由于常有狂风和雪崩，霍迪尔之子建议在冒险进入危险的风暴峭壁时，至少带上两名同伴。", 2, "|cFFFFD200商人：|r李奥霍夫|n|cFFFFD200区域：|r风暴峭壁|n|cFFFFD200阵营：|r霍迪尔之子 - 崇拜|n|cFFFFD200花费：|r10000|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [61983] = { 32931, 0, },
    [61996] = { 31239, 1, 132, "蓝色龙鹰", "龙鹰是已知的最致命掠食者之一。它们能从很远的距离发现猎物，俯冲而下，用利爪和喙将猎物撕碎。", 5, "|cFFFFD200成就：|r坐骑堆积如山|n|cFFFFD200分类：|r综合" },
    [61997] = { 32944, 1, 132, "红色龙鹰", "龙鹰是已知的最致命掠食者之一。它们能从很远的距离发现猎物，俯冲而下，用利爪和喙将猎物撕碎。", 5, "|cFFFFD200成就：|r坐骑堆积如山|n|cFFFFD200分类：|r综合" },
    [62048] = { 25064, 1, 192, "伊利达雷末日龙鹰", "每年都有一次，时间的裂缝会出现，奇怪的事情随之发生。伊利达雷斥候和末日行者非常惊讶地发现自己身处塔纳利斯。", 0, "|cFFFFD200掉落：|r 末日行者|n|cFFFFD200区域：|r 塔纳利斯" },
    [63232] = { 33297, 2, 0, "暴风城军马", "尽管在暴风城长大，但这个品种对冰冠冰川的寒冷天气表现出了非凡的适应力。", 2, "|cFFFFD200商人：|r亚瑟·弗卢下士|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [63635] = { 33299, 2, 0, "暗矛迅猛龙", "这种迅猛龙原本由达克莱伊培育，但后来被诺森德的暗矛部族收留。", 2, "|cFFFFD200商人：|r萨曼巴|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [63636] = { 33408, 2, 0, "铁炉堡山羊", "蛮锤事实核查员声称，这个特殊的品种是矮人在定居丹莫罗时最早驯化的山羊种类。", 2, "|cFFFFD200商人：|r德里克·布林德比尔德|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [63637] = { 33298, 2, 0, "达纳苏斯夜刃豹", "当暗夜精灵的坐骑牺牲时，骑手通常会保留这只黑豹的一颗巨大獠牙作为纪念。", 2, "|cFFFFD200商人：|r鲁克·鹰拳|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [63638] = { 33301, 2, 0, "诺莫瑞根机械陆行鸟", "当你必须、绝对要马上赶到那里时。——里利·斯宾德纳特", 2, "|cFFFFD200商人：|r里利·斯宾德纳特|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [63639] = { 33416, 2, 0, "埃索达雷象", "埃索达雷象是受过纳鲁奥罗护佑的雷象，奥罗曾随先知维伦及其追随者一起从德拉诺来到艾泽拉斯。", 2, "|cFFFFD200商人：|r伊蕾丝|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [63640] = { 33409, 2, 0, "奥格瑞玛战狼", "曾有很短的一段时间，许多兽人会宣称自己“饿得像头奥格瑞玛战狼”。一些血精灵仍会讽刺性地使用这个短语。", 2, "|cFFFFD200商人：|r弗雷卡·血斧|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [63641] = { 33300, 2, 0, "雷霆崖科多兽", "作为兽群的首领，这头科多兽是莫高雷雷霆万钧的强大生物的绝佳典范。", 2, "|cFFFFD200商人：|r多鲁·雷角|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [63642] = { 33418, 2, 0, "银月城陆行鸟", "所以我说我今晚想吃鸡。接下来我一躺下，那东西就试图尝尝我的眼珠子是什么味道。——博兹尔·冲击弩", 2, "|cFFFFD200商人：|r特雷利斯·晨阳|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [63643] = { 33414, 2, 0, "被遗忘者战马", "当阵亡的英雄被复活为亡灵时，他们的战马也一样。", 2, "|cFFFFD200商人：|r伊丽莎·基连|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [63796] = { 33848, 1, 128, "米米尔隆的头部", "上古之神尤格-萨隆收藏的一件泰坦工艺的信物。是目前艾泽拉斯最大的机械侏儒头部。", 0, "|cFFFFD200掉落：|r 尤格-萨隆|n|cFFFFD200地点：|r 奥杜尔" },
    [63844] = { 33857, 1, 128, "银色角鹰兽", "银色角鹰兽只与最勇敢、最身经百战的勇士结成伙伴。", 2, "|cFFFFD200商人：|r阵营军需官|n|cFFFFD200地点：|r 冰冠冰川，银色比武场|n|cFFFFD200花费：|r150|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t|n" },
    [63956] = { 33892, 1, 128, "铁箍始祖幼龙", "它的皮肤比黄铜还要坚硬，没有任何剑或矛能将其刺穿或伤害。", 5, "|cFFFFD200成就：|r奥杜尔团队的荣耀（25人）|n|cFFFFD200分类：|r地下城和团队副本" },
    [63963] = { 33904, 1, 128, "铁锈始祖幼龙", "不像另一只那么闪亮，但这依然是个伟大的发现，小伙子们。——布莱恩·铜须", 5, "|cFFFFD200成就：|r奥杜尔团队的荣耀（10人）|n|cFFFFD200分类：|r地下城和团队副本" },
    [64656] = { 34154, 2, 64, "蓝色骷髅战马", "罕见的景象。自从瑞文戴尔男爵统治斯坦索姆后，大多数就消失了。", 2, "|cFFFFD200绝版|r" },
    [64657] = { 34155, 2, 0, "白色科多兽", "“科多兽是我们人民的脊梁。无论部落走到哪里——贸易、定居或战争——你都会看到强大的科多兽。” —— 哈布·爪蹄", 2, "|cFFFFD200商人：|r哈布·爪蹄|n|cFFFFD200区域：|r莫高雷|n|cFFFFD200花费：|r1|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [64658] = { 356, 2, 0, "黑狼", "嚎叫声极大，数英里外都能听见。", 2, "|cFFFFD200商人：|r奥古纳罗·狼行者|n|cFFFFD200区域：|r奥格瑞玛|n|cFFFFD200花费：|r1|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [64659] = { 34156, 2, 4, "毒皮暴掠龙", "你把这个小家伙从一个满是鳞片的幼崽养大——莫维克一定会为你感到骄傲的。但他还是会让你把这小家伙在角落里弄出的那一团糟给清理干净。", 1, "|cFFFFD200任务：|r它们长得真快|n|cFFFFD200区域：|r安戈洛环形山" },
    [64681] = { 32198, 1, },
    [64731] = { 34187, 2, 2192, "海龟", "这些坐骑往往在幼年时期就被渔民捕获，它们在水里比在陆地上舒适得多。", 3, "|cFFFFD200专业：|r 钓鱼|n" },
    [64761] = { 32208, 1, },
    [64927] = { 34225, 1, 192, "致命角斗士的冰霜巨龙", "这些被重新复活的毁灭化身并不畏惧死亡；它们是死亡的散布者。", 2, "|cFFFFD200绝版|r" },
    [64977] = { 34238, 2, 0, "黑色骸骨战马", "被遗忘者认为，如果失去目标，即使是驮兽在死后也会遭受痛苦。", 2, "|cFFFFD200商人：|r撒迦利亚·普斯特|n|cFFFFD200区域：|r提瑞斯法林地|n|cFFFFD200花费：|r1|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [64992] = { 31319, 2, },
    [64993] = { 31319, 2, },
    [65439] = { 34425, 1, 192, "狂怒角斗士的冰霜巨龙", "艾泽拉斯一些最强大的巨龙被跨越生与死的帷幕召唤而来，以不朽的忠诚效忠新主人。", 2, "|cFFFFD200绝版|r" },
    [65637] = { 34551, 2, 0, "大型红色雷象", "在纳格兰从未见过，第一批红色雷象幼崽是在埃索达坠毁后于艾泽拉斯出生的。一些饲养员猜测，这种独特的颜色不知何故是由蹂躏秘血岛的相同辐射造成的。", 2, "|cFFFFD200商人：|r伊蕾丝|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r500|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t5|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [65638] = { 34550, 2, 0, "迅捷月刃豹", "许多暗夜精灵崇敬这些骄傲的坐骑，因为它们闪闪发光的皮毛象征着月亮女神艾露恩。", 2, "|cFFFFD200商人：|r鲁克·鹰拳|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r500|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t5|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [65639] = { 34556, 2, 0, "迅捷红色陆行鸟", "你问这是染色的吗？哦，这鸟啊。我们确实给红色稍微润了润色。——特雷利斯·晨阳", 2, "|cFFFFD200商人：|r特雷利斯·晨阳|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r500|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t5|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [65640] = { 34557, 2, 0, "迅捷灰马", "经历了银色北伐军最艰苦的几场战斗的老兵。", 2, "|cFFFFD200商人：|r亚瑟·弗卢下士|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r500|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t5|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [65641] = { 34558, 2, 4, "大型金色科多兽", "作为兽群的首领，这头科多兽是南贫瘠之地雷霆万钧的强大生物的绝佳典范。", 2, "|cFFFFD200商人：|r多鲁·雷角|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r500|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t5|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [65642] = { 34553, 2, 0, "涡轮陆行鸟", "后视镜不是为了让你往后看，而是为了让你的敌人除了你的排气管还能看到点别的。——里利·斯宾德纳特", 2, "|cFFFFD200商人：|r里利·斯宾德纳特|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r500|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t5|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [65643] = { 34554, 2, 0, "迅捷紫山羊", "巴拉克·托尔奥山羊厚实的骨质头骨和巨大的角，使其成为在全副武装的敌群中冲锋陷阵的理想坐骑。", 2, "|cFFFFD200商人：|r德里克·布林德比尔德|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r500|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t5|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [65644] = { 34549, 2, 0, "迅捷紫色迅猛龙", "这些丛林猎手是巨魔的长期盟友，它们与主人建立了特殊的纽带。它们成为了坐骑、守卫和朋友。", 2, "|cFFFFD200商人：|r萨曼巴|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r500|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t5|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [65645] = { 34552, 2, 0, "白色骷髅战马", "当阵亡的英雄被复活为亡灵时，他们的战马也一样。", 2, "|cFFFFD200商人：|r伊丽莎·基连|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r500|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t5|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [65646] = { 34555, 2, 0, "迅捷酒红狼", "部落的狼是交心的朋友，而不是被驯化的牲畜。", 2, "|cFFFFD200商人：|r弗雷卡·血斧|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r500|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t5|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [65917] = { 34655, 2, 64, "魔法公鸡", "魔法在一个天才手中，可以创造出奇妙的、不可思议的事物。魔法在一个白痴手中，可以变出一只巨大的公鸡。", 8, "|cFFFFD200集换式卡牌：|r 艾尔·波罗·格兰德" },
    [66087] = { 35147, 1, 132, "银色盟约角鹰兽", "银色盟约的角鹰兽无论对它们的骑手还是对联盟，都极其忠诚。", 2, "|cFFFFD200商人：|r海伦·兰歌|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200阵营：|r银色盟约 - 崇拜|n|cFFFFD200花费：|r150|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [66088] = { 35148, 1, 132, "夺日者龙鹰", "达拉然的夺日者只会挑选最快、最强大的龙鹰作为他们的坐骑。", 2, "|cFFFFD200商人：|r瓦萨林·红晨|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200阵营：|r夺日者 - 崇拜|n|cFFFFD200花费：|r150|Hcurrency:241|h|TInterface\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t|h" },
    [66090] = { 33840, 2, 4, "奎尔多雷战马", "来自于曾经在永恒之井海岸附近吃草的优良马匹血统。", 2, "|cFFFFD200商人：|r海伦·兰歌|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200阵营：|r银色盟约 - 崇拜|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [66091] = { 33841, 2, 4, "夺日者陆行鸟", "我要求在战场上展现出速度、优雅和纪律。这一只将非常出色。——艾蕾希亚·晨歌", 2, "|cFFFFD200商人：|r瓦萨林·红晨|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200阵营：|r夺日者 - 崇拜|n|cFFFFD200花费：|r100|Hcurrency:241|h|TInterface\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t|h" },
    [66122] = { 34655, 2, 64, "魔法公鸡", "魔法在一个天才手中，可以创造出奇妙的、不可思议的事物。魔法在一个白痴手中，可以变出一只巨大的公鸡。", 8, "|cFFFFD200集换式卡牌：|r 艾尔·波罗·格兰德" },
