    [66846] = { 35169, 2, 0, "赭色骷髅战马", "当阵亡的英雄被复活为亡灵时，他们的战马也一样。", 2, "|cFFFFD200商人：|r撒迦利亚·普斯特|n|cFFFFD200区域：|r提瑞斯法林地|n|cFFFFD200花费：|r10|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [66847] = { 35168, 2, 0, "条纹晨刃豹", "暗夜精灵曾认为在野外看到这种浅色豹子品种是不祥之兆。", 2, "|cFFFFD200商人：|r兰兰尼|n|cFFFFD200区域：|r泰达希尔|n|cFFFFD200花费：|r1|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [66906] = { 35179, 2, 0, "银色军马", "经过训练，只接受圣光的勇士作为骑手。", 2, "|cFFFFD200商人：|r艾弗妮基·卡普萨里斯女士|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t|n" },
