    [67336] = { 35362, 1, 192, "无情角斗士的冰霜巨龙", "在生前，它无法被驯服，但现在死灵法术和深奥的束缚仪式结合在一起，使这只不屈的生物屈服于骑手的意志。", 5, "|cFFFFD200绝版|r" },
    [67466] = { 35445, 2, 0, "银色战马", "只授予那些在银色比武场证明自己是勇士的人。", 2, "|cFFFFD200商人：|r艾弗妮基·卡普萨里斯女士|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [68056] = { 35809, 2, 4, "迅捷部落战狼", "银色北伐军最快的一批坐骑，被奖赏给那些在冰冠冰川的比赛中表现出色的部落成员。", 0, "|cFFFFD200掉落：|r 银色北伐军的贡品宝箱|n|cFFFFD200地点：|r 大十字军的试炼（10人）" },
    [68057] = { 35808, 2, 4, "迅捷联盟战马", "银色北伐军最快的一批坐骑，被奖赏给那些在冰冠冰川的比赛中表现出色的联盟成员。", 0, "|cFFFFD200掉落：|r 银色北伐军的贡品宝箱|n|cFFFFD200地点：|r 大十字军的试炼（10人）" },
    [68187] = { 35876, 2, 4, "十字军的白色战马", "只授予大十字军试炼中最熟练的冠军，这些战马是专门为联盟成员从提里奥·弗丁的私人兽栏中挑选出来的。", 5, "|cFFFFD200成就：|r献给不朽的贡品|n|cFFFFD200分类：|r光辉事迹" },
    [68188] = { 35878, 2, 4, "十字军的黑色战马", "只授予大十字军试炼中最熟练的冠军，这些战马是专门为部落成员从提里奥·弗丁的私人兽栏中挑选出来的。", 5, "|cFFFFD200成就：|r献给不朽的贡品|n|cFFFFD200分类：|r光辉事迹" },
