    [69395] = { 36837, 1, 128, "奥妮克希亚幼龙", "她和她母亲有很多共同点，除了被杀和复活之外。不过她还年轻。——马洛拉克", 0, "|cFFFFD200掉落：|r 奥妮克希亚|n|cFFFFD200区域：|r 奥妮克希亚的巢穴" },
