    [71810] = { 38361, 1, 192, "暴怒角斗士的冰霜巨龙", "许多人相信在它们早期的生命中，这些巨龙被迫为了取悦他人而与同类自相残杀。也许这就是它们特别好斗的原因。", 5, "|cFFFFD200绝版|r" },
