    [72286] = { 38545, 2, 0, "无敌", "阿尔萨斯·米奈希尔著名的战马，生前死后都忠诚地服务于它的主人。能骑上它绝对是实力的象征。", 0, "|cFFFFD200掉落：|r 巫妖王|n|cFFFFD200区域：|r 冰冠堡垒" },
    [72807] = { 38695, 1, 128, "冰河踏破者", "从冰冠冰川令人不寒而栗的深渊中复活，冰霜巨龙镇压者被认为是所有冰霜巨龙中最凶猛和最无情的。", 5, "|cFFFFD200成就：|r冰冠堡垒团队的荣耀（25人）|n|cFFFFD200分类：|r地下城和团队副本" },
    [72808] = { 38778, 1, 128, "浴血冰霜巨龙镇压者", "当确定一条复活的冰霜巨龙死得特别惨烈和血腥时，它就会被赋予浴血镇压者的名字。", 5, "|cFFFFD200成就：|r冰冠堡垒团队的荣耀（10人）|n|cFFFFD200分类：|r地下城和团队副本" },
    [73313] = { 39046, 2, 0, "猩红死亡战马", "被安置在冰冠堡垒中，为巫妖王最宠信的仆从提供服务。", 1, "|cFFFFD200任务：|r 莫格莱尼的重聚|n|cFFFFD200区域：|r 冰冠堡垒" },
