    [74918] = { 40191, 2, 64, "白毛犀牛", "由托比·“鹅妈妈”·铁锤在北风苔原捕获，这头毛茸茸的野兽被侏儒套上缰绳后一直怀恨在心。", 8, "|cFFFFD200集换式卡牌：|r 白毛犀牛" },
